import fs from 'fs';
import { google } from 'googleapis';
import { Agent, LocalAgentConfig } from '@google/antigravity';

async function runDriveDocsPipeline() {
  if (!fs.existsSync('token.json')) {
    console.error("token.json not found! Run Module 1 first.");
    return;
  }
  const tokenData = JSON.parse(fs.readFileSync('token.json', 'utf8'));
  const auth = google.auth.fromJSON(tokenData);

  const drive = google.drive({ version: 'v3', auth });
  const docs = google.docs({ version: 'v1', auth });

  // Search for the document
  console.log("Searching for document...");
  const query = "name = 'AGY-311 Work Doc' and mimeType = 'application/vnd.google-apps.document'";
  const searchResults = await drive.files.list({ q: query, fields: 'files(id, name)' });
  const files = searchResults.data.files || [];

  let docId;
  if (files.length === 0) {
    console.log("Creating document...");
    const newFile = await drive.files.create({
      requestBody: {
        name: 'AGY-311 Work Doc',
        mimeType: 'application/vnd.google-apps.document'
      },
      fields: 'id'
    });
    docId = newFile.data.id;
    await docs.documents.batchUpdate({
      documentId: docId,
      requestBody: {
        requests: [{
          insertText: {
            text: "Project Kickoff Notes\n\nRaw Transcript:\nThe client wants a system that is secure, runs inside distrobox, and logs all tool execution approvals. We need to deploy this by Q3.",
            location: { index: 1 }
          }
        }]
      }
    });
  } else {
    docId = files[0].id;
  }

  // Get document body
  console.log(`Reading document body for ID: ${docId}`);
  const doc = await docs.documents.get({ documentId: docId });
  const content = doc.data.body?.content || [];
  let rawText = '';
  for (const element of content) {
    if (element.paragraph) {
      for (const run of element.paragraph.elements || []) {
        if (run.textRun) {
          rawText += run.textRun.content;
        }
      }
    }
  }

  // Run Agent turn
  console.log("Summarizing doc content...");
  const config = new LocalAgentConfig({
    systemInstruction: "You are a business writer. Summarize transcripts into clean, bulleted Action Items."
  });
  const agent = new Agent(config);
  await agent.start();

  let summary;
  try {
    const response = await agent.chat(`Summarize this project content:\n\n<doc>\n${rawText}\n</doc>`);
    summary = await response.text();
  } finally {
    await agent.stop();
  }

  // Append back to document
  const docDetails = await docs.documents.get({ documentId: docId });
  const docContent = docDetails.data.body?.content || [];
  const lastElement = docContent[docContent.length - 1];
  const endIndex = lastElement.endIndex || 1;

  console.log("Appending summary...");
  await docs.documents.batchUpdate({
    documentId: docId,
    requestBody: {
      requests: [{
        insertText: {
          text: `\n\n--- Asynchronous Agent Summary ---\n${summary}`,
          location: { index: endIndex - 1 }
        }
      }]
    }
  });
  console.log(`Success! Doc updated. https://docs.google.com/document/d/${docId}/edit`);
}

runDriveDocsPipeline().catch(console.error);
